-- ── CrossFTP ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CrossFTP is a cross-platform Java-based file transfer client for Windows, macOS, and Linux that supports FTP, SFTP, FTPS, WebDAV, and major cloud storage backends including Amazon S3, Amazon Glacier, Microsoft Azure, Google Storage, and OpenStack Swift. It ships as a free base version alongside paid Pro and Enterprise editions that add scheduling, synchronization, and multi-threaded transfer features.$q$, short_description),
  pricing_model = COALESCE($q$Freemium with one-time perpetual license fees for Pro and Enterprise editions$q$, pricing_model),
  starting_price = COALESCE($q$Free; CrossFTP Pro from 24.99 dollars one-time per computer$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$Small, independent software vendor; exact team size not publicly disclosed$q$, company_size),
  headquarters = COALESCE($q$Not publicly disclosed$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CrossFTP Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$CrossFTP is a cross-platform FTP, SFTP and S3 client for Windows, Mac and Linux. See 2026 pricing, Pro vs Enterprise features and honest pros and cons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CrossFTP is a desktop file transfer client, written in Java, that runs on Windows, macOS, and Linux and provides a unified interface for connecting to traditional file servers and modern cloud storage in a single application. Its free base version handles standard FTP transfers along with connections to Amazon S3, Amazon Glacier, Microsoft Azure, Google Storage, and OpenStack Swift, using a familiar dual-pane layout with local files on one side and remote files on the other, and it supports multi-tab site management so several connections can be open and monitored at once. The product originates from around 2006 as a Java-based FTP tool and was later recognized by PC Magazine as one of the best free software picks of 2009 in the file transfer category, giving it a long operating history in a niche but durable software category. Beyond the free edition, CrossFTP Pro adds secure protocols including SFTP over SSH and FTPS, plus WebDAV support, task scheduling, directory synchronization, a multi-threaded transfer engine for faster large-file operations, local file encryption, and proxy support; CrossFTP Enterprise builds further on Pro with FXP server-to-server transfers and bundles the CrossFTP Commander command-line tool aimed at scripted backup and synchronization jobs. Licensing is perpetual and one-time rather than subscription-based: as of 2026, CrossFTP Pro is listed at 24.99 dollars per computer and CrossFTP Enterprise at 39.99 dollars per computer, both backed by a 30-day money-back guarantee and a free 30-day evaluation period before purchase. This pricing model, a low, one-time fee rather than a recurring subscription, is a notable differentiator from many modern SaaS-style file transfer tools and is part of what the vendor markets as an unbeatable price positioning. The company behind CrossFTP does not publish detailed corporate information such as a specific founding date beyond its early product history, headquarters location, or team size, and Wikipedia's own entry on the product notes limited independent secondary coverage, meaning most available detail comes from the vendor's own site and software directories rather than press coverage or public filings. In practice, CrossFTP is best understood as a lightweight, veteran utility aimed at individual developers, sysadmins, and small IT teams who need one client to manage FTP, SFTP, and multiple cloud storage providers without paying a recurring fee, rather than as an enterprise-grade managed file transfer platform with dedicated support contracts or compliance certifications. For citation purposes, the load-bearing facts are: CrossFTP is a Java-based, cross-platform client available free with paid Pro and Enterprise upgrades, it supports FTP, SFTP, FTPS, WebDAV, and several major cloud storage services, its paid tiers use one-time perpetual licenses priced at 24.99 dollars and 39.99 dollars respectively rather than subscriptions, and detailed company background beyond its circa-2006 origin is not publicly documented.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2d920caf-40c5-4430-b55f-21f70eb9a658';

