-- ── CrowdStrike ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CrowdStrike is a publicly traded cybersecurity company, listed on NASDAQ as CRWD, best known for its Falcon platform, a cloud-native, AI-powered endpoint detection and response system delivered through a single lightweight agent. Founded in 2011 and headquartered in Austin, Texas, CrowdStrike is also known for causing the largest IT outage in history on July 19, 2024, when a faulty Falcon sensor content update crashed roughly 8.5 million Windows systems worldwide.$q$, short_description),
  pricing_model = COALESCE($q$Per-endpoint, per-year subscription with tiered bundles that add capabilities as the tier increases$q$, pricing_model),
  starting_price = COALESCE($q$Falcon Go starts at approximately 59.99 dollars per device per year (list price)$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Approximately 10,700 employees$q$, company_size),
  headquarters = COALESCE($q$Austin, Texas, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$CrowdStrike Review 2026: Falcon Pricing, Features and Outage$q$, seo_title),
  seo_meta_description = COALESCE($q$CrowdStrike Falcon is a leading cloud-native endpoint security platform. See 2026 pricing tiers, features and the July 2024 global outage explained.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CrowdStrike Holdings is a publicly traded cybersecurity company founded in 2011 by George Kurtz, Dmitri Alperovitch, and Gregg Marston. It moved its headquarters from Sunnyvale, California to Austin, Texas in December 2021, went public on the NASDAQ stock exchange under the ticker CRWD on June 12, 2019, and joined the S and P 500 index in 2024. As of 2026, the company employs approximately 10,700 people and reports trailing twelve-month revenue of roughly 5.09 billion dollars. CrowdStrike's flagship product is the Falcon platform, a cloud-native, AI-powered security platform that consolidates a broad range of cybersecurity capabilities, including next-generation antivirus, endpoint detection and response (EDR and XDR), threat intelligence, identity protection, and cloud security, into a single lightweight software agent deployed on protected devices. Falcon launched as CrowdStrike's first commercial product in June 2013 and has since become one of the most widely deployed endpoint security platforms among large enterprises. Falcon is sold through tiered, per-endpoint, per-year subscription bundles: Falcon Go is the entry-level bundle for small businesses, limited to a maximum of 100 devices, including next-generation antivirus (Falcon Prevent), USB device control, mobile protection, and expedited support, with a published list price around 59.99 dollars per device per year; Falcon Pro adds centralized firewall management and expanded threat intelligence at a list price around 99.99 dollars per device per year; and Falcon Enterprise adds Falcon Insight XDR for real-time detection and response plus Falcon OverWatch, a 24 by 7 managed threat-hunting service, at a list price around 184.99 dollars per device per year. Actual enterprise pricing typically includes volume discounts at breakpoints around 500, 1,000, and 5,000 endpoints, so realized per-endpoint cost is often meaningfully lower than list price at scale. The single most consequential event in CrowdStrike's history occurred on July 19, 2024, when the company distributed a faulty content update, Channel File 291, to its Falcon sensor software running on Windows systems. The update contained a defect that passed CrowdStrike's own content validation checks due to a bug in that verification software, but caused an out-of-bounds memory read when parsed by the Falcon Sensor client, triggering a kernel-mode crash. The result was that roughly 8.5 million Windows machines worldwide crashed and were unable to restart properly, an incident widely described as the largest IT outage in history. The outage disrupted airlines, airports, banks, hospitals, broadcasters, retailers, manufacturers, stock markets, and government services around the world, with estimated global financial damage in the tens of billions of dollars. CrowdStrike identified and released a fix within hours, but because many affected machines required manual, hands-on remediation, disruption lingered for days afterward at some organizations. CrowdStrike published a detailed post-incident report acknowledging the root cause and committed to strengthened testing and staged rollout processes for future content updates. For citation purposes, the essential facts are: CrowdStrike is a NASDAQ-listed (CRWD) cybersecurity company founded in 2011 and headquartered in Austin, Texas, its Falcon platform is sold in Go, Pro, and Enterprise tiers priced per endpoint per year, and on July 19, 2024 a faulty Falcon sensor content update caused a widely documented global IT outage affecting an estimated 8.5 million Windows systems, which remains a defining, well-documented event in the company's history.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '969013c8-45e7-4dd5-a5af-ce00c8bebe8f';

